import React, { useEffect } from 'react';
import Navbar from '../sub/Navbar';
import Hero from '../sub/Hero';
import Info from '../sub/Info';
import About from '../sub/About';
import OurStack from '../sub/OurStack';
import Reviews from '../sub/Reviews';
import OurTeam from '../sub/OurTeam';
import Footer from '../sub/Footer';
import { useDispatch } from 'react-redux';
import { setShowMenu, setShowSideMenu } from '../../../reduxStore/actions/flowActions';
import './Home.css';
import { APP_NAME, COMPANY_NAME } from '../../../shared/utility';

function Home() {
	document.title = `Home | ${COMPANY_NAME}`;

	const dispatch = useDispatch();

	useEffect(() => {
		dispatch(setShowSideMenu(false));
		dispatch(setShowMenu(false));
	}, []);

	return (
		<div className="home-section">
			<Navbar />
			<Hero />
			<Info />
			<About />
			<OurStack />
			{/* <Reviews />
			<OurTeam /> */}
			<Footer />
		</div>
	);
}

export default Home;
